import cadquery as cq

def make_tool(axis, s1, s2, size, steps):
    step = size / steps
    pts = [(0, 0), (size, 0)]
    for i in range(steps):
        pts.append((size - i * step, (i + 1) * step))
        if i < steps - 1:
            pts.append((size - (i + 1) * step, (i + 1) * step))
    pts.append((0, size))

    rot_map = {(-1, -1): 0, (1, -1): 90, (1, 1): 180, (-1, 1): 270}
    rot = rot_map[(s1, s2)]

    if axis == 'Z':
        tool = cq.Workplane("XY").polyline(pts).close().extrude(100).translate((0, 0, -50))
        tool = tool.rotate((0, 0, 0), (0, 0, 1), rot)
        return tool.translate((s1 * 50, s2 * 50, 0))

    elif axis == 'X':
        tool = cq.Workplane("YZ").polyline(pts).close().extrude(100).translate((-50, 0, 0))
        tool = tool.rotate((0, 0, 0), (1, 0, 0), rot)
        return tool.translate((0, s1 * 50, s2 * 50))

    elif axis == 'Y':
        tool = cq.Workplane("XZ").polyline(pts).close().extrude(100).translate((0, 50, 0))
        tool = tool.rotate((0, 0, 0), (0, -1, 0), rot)
        return tool.translate((s1 * 50, 0, s2 * 50))

